		strokeWidth: 1,
		stroke: primaryColor,
		fill,
		widgets: {},
		widgetSize: 6,
		widgetStrokeWidth: 1,
		widgetStroke: whiteColor,
		autofillSize: 6,
		autofillStrokeWidth: 1,
		autofillStroke: whiteColor,
		rowHeaderFill: fill,
		rowHeaderStroke: primaryColor,
		rowHeaderStrokeWidth: 1,
		columnHeaderFill: fill,
		columnHeaderStroke: primaryColor,
		columnHeaderStrokeWidth: 1,
