const TEXT_TO_NUMBER_CONTEXT_MENU_ID = "sheet.contextMenu.text-to-number";
function Text2NumberContextMenuItemFactory(accessor) {
	return {
		id: TEXT_TO_NUMBER_CONTEXT_MENU_ID,
		commandId: TextToNumberCommand.id,
		type: MenuItemType.BUTTON,
		title: "sheets-ui.rightClick.textToNumber",
		icon: "PipingIcon",
		disabled$: getObservableWithExclusiveRange$(accessor, getCurrentRangeDisable$(accessor, {
			workbookTypes: [WorkbookEditablePermission],
			worksheetTypes: [WorksheetEditPermission, WorksheetSetCellValuePermission],
			rangeTypes: [RangeProtectionPermissionEditPoint]
		})),
		hidden$: combineLatest([getMenuHiddenObservable(accessor, UniverInstanceType.UNIVER_SHEET), getMenuHiddenByCurrentSelectionChangedObservable$(accessor)]).pipe(map(([menuHidden, selectionHidden]) => menuHidden || selectionHidden))
	};
}

